external_knowledge:
'v1.0' is the version number for the models under consideration;
'low RMSE by user score' refers to models where the RMSE by user is less than 0.9;
'early days of October 2023' specifically refers to the period between '2023-10-01' and '2023-10-02'.

sql:
SELECT DISTINCT model_id
FROM performance_metrics
WHERE ndcg = (
    SELECT MAX(ndcg)
    FROM performance_metrics
);

SELECT rmse_by_user
FROM performance_metrics
WHERE model_id = 1;

SELECT model_version
FROM performance_metrics
WHERE rmse_by_user < (
    SELECT AVG(rmse_by_user)
    FROM performance_metrics
);

